/**
 * @summary Export assets to Excel
 */
export const getExportAssetsUrl = (params?: ExportAssetsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/export-assets?${stringifiedParams}`
    : `/api/export-assets`;
};

export const exportAssets = async (
  params?: ExportAssetsParams,
  options?: RequestInit,
): Promise<Blob> => {
  return customFetch<Blob>(getExportAssetsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getExportAssetsQueryKey = (params?: ExportAssetsParams) => {
  return [`/api/export-assets`, ...(params ? [params] : [])] as const;
};

export const getExportAssetsQueryOptions = <
  TData = Awaited<ReturnType<typeof exportAssets>>,
  TError = ErrorType<unknown>,
>(
  params?: ExportAssetsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof exportAssets>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getExportAssetsQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof exportAssets>>> = ({
    signal,
  }) => exportAssets(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof exportAssets>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ExportAssetsQueryResult = NonNullable<
  Awaited<ReturnType<typeof exportAssets>>
>;
export type ExportAssetsQueryError = ErrorType<unknown>;

/**
 * @summary Export assets to Excel
 */

export function useExportAssets<
  TData = Awaited<ReturnType<typeof exportAssets>>,
  TError = ErrorType<unknown>,
>(
  params?: ExportAssetsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof exportAssets>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getExportAssetsQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
